INSERT INTO `employee_tone_profiles` VALUES
(1,1,2,'Сотрудник использует вежливый и информативный стиль общения, предлагая помощь и предоставляя конкретные детали.','[\"\\u0417\\u0434\\u0440\\u0430\\u0432\\u0441\\u0442\\u0432\\u0443\\u0439\\u0442\\u0435! \\u0415\\u0441\\u043b\\u0438 \\u0443 \\u0432\\u0430\\u0441 \\u0435\\u0441\\u0442\\u044c \\u0432\\u043e\\u043f\\u0440\\u043e\\u0441\\u044b, \\u0434\\u0430\\u0439\\u0442\\u0435 \\u0437\\u043d\\u0430\\u0442\\u044c.\",\"\\u0417\\u0434\\u0440\\u0430\\u0432\\u0441\\u0442\\u0432\\u0443\\u0439\\u0442\\u0435! \\u041c\\u044b \\u043f\\u0440\\u0435\\u0434\\u043e\\u0441\\u0442\\u0430\\u0432\\u043b\\u044f\\u0435\\u043c \\u0443\\u0441\\u043b\\u0443\\u0433\\u0438 \\u043f\\u043e \\u043c\\u0430\\u043d\\u0438\\u043a\\u044e\\u0440\\u0443.\",\"\\u0417\\u0434\\u0440\\u0430\\u0432\\u0441\\u0442\\u0432\\u0443\\u0439\\u0442\\u0435! \\u0423 \\u043d\\u0430\\u0441 \\u0435\\u0441\\u0442\\u044c \\u0442\\u043e\\u0432\\u0430\\u0440 \'\\u0441\\u0438\\u043a\\u0441 \\u0441\\u0435\\u0432\\u0435\\u043d\'.\",\"\\u0415\\u0441\\u043b\\u0438 \\u0443 \\u0432\\u0430\\u0441 \\u0435\\u0441\\u0442\\u044c \\u0434\\u043e\\u043f\\u043e\\u043b\\u043d\\u0438\\u0442\\u0435\\u043b\\u044c\\u043d\\u044b\\u0435 \\u0432\\u043e\\u043f\\u0440\\u043e\\u0441\\u044b, \\u0434\\u0430\\u0439\\u0442\\u0435 \\u0437\\u043d\\u0430\\u0442\\u044c!\",\"\\u042f \\u0441 \\u0440\\u0430\\u0434\\u043e\\u0441\\u0442\\u044c\\u044e \\u043f\\u043e\\u043c\\u043e\\u0433\\u0443!\",\"\\u0423\\u0441\\u043b\\u0443\\u0433\\u0430 \'\\u043d\\u043e\\u0433\\u043e\\u0442\\u043e\\u0447\\u043a\\u0438\' \\u0434\\u043b\\u0438\\u0442\\u0441\\u044f 60 \\u043c\\u0438\\u043d\\u0443\\u0442.\",\"\\u0426\\u0435\\u043d\\u0430 \\u0441\\u043e\\u0441\\u0442\\u0430\\u0432\\u043b\\u044f\\u0435\\u0442 5000 \\u0440\\u0443\\u0431\\u043b\\u0435\\u0439.\",\"\\u0415\\u0441\\u043b\\u0438 \\u0445\\u043e\\u0442\\u0438\\u0442\\u0435 \\u0437\\u0430\\u043f\\u0438\\u0441\\u0430\\u0442\\u044c\\u0441\\u044f, \\u0434\\u0430\\u0439\\u0442\\u0435 \\u0437\\u043d\\u0430\\u0442\\u044c!\",\"\\u0426\\u0435\\u043d\\u0430 \\u0442\\u043e\\u0432\\u0430\\u0440\\u0430 \\u0441\\u043e\\u0441\\u0442\\u0430\\u0432\\u043b\\u044f\\u0435\\u0442 6767 \\u0440\\u0443\\u0431\\u043b\\u0435\\u0439.\",\"\\u0425\\u043e\\u0442\\u0438\\u0442\\u0435 \\u0443\\u0437\\u043d\\u0430\\u0442\\u044c \\u0431\\u043e\\u043b\\u044c\\u0448\\u0435? \\u0421\\u043f\\u0440\\u0430\\u0448\\u0438\\u0432\\u0430\\u0439\\u0442\\u0435!\",\"\\u041c\\u044b \\u0432\\u0441\\u0435\\u0433\\u0434\\u0430 \\u0433\\u043e\\u0442\\u043e\\u0432\\u044b \\u043f\\u043e\\u043c\\u043e\\u0447\\u044c!\",\"\\u041d\\u0435 \\u0441\\u0442\\u0435\\u0441\\u043d\\u044f\\u0439\\u0442\\u0435\\u0441\\u044c \\u0437\\u0430\\u0434\\u0430\\u0432\\u0430\\u0442\\u044c \\u0432\\u043e\\u043f\\u0440\\u043e\\u0441\\u044b!\"]','{\"samples_count\":3,\"source\":\"openai\",\"chat_id\":44}','2026-05-12 16:20:39','2026-05-12 16:13:53','2026-05-12 16:20:39'),
(2,1,3,'Сотрудник использует неформальный, разговорный стиль общения, часто прибегает к сленгу и коротким фразам. Сообщения содержат много повторений и неформальных выражений.','[\"\\u0441\\u0430\\u043b\\u0430\\u043c\",\"\\u0431\\u0440\\u0430\\u0442\",\"\\u0447\\u0435 \\u0442\\u0430\\u043c \\u0431\\u0440\\u0430\\u0442\\u0430\\u043d\",\"\\u043f\\u0440 \\u043f\\u0440 \\u043f\\u0440 \\u043f\\u0430\\u0442\\u0430\\u043f\\u0438\\u043c\",\"\\u0431\\u0430\\u043d\\u0430\\u043d\\u044b\",\"\\u043f\\u0440\\u043e\\u0434\\u0430\\u044e\",\"\\u0438 \\u0442\\u0430\\u043f\\u043e\\u0447\\u043a\\u0438\",\"\\u043d\\u0430\\u0445\",\"\\u043b\\u0430\",\"\\u0447\\u043e\\u0440\\u0430\\u043c\",\"\\u0431\\u043b\\u044f \\u043e\\u043d \\u0447\\u043e\\u0440\\u0430\\u043c \\u043d\\u0435 \\u043f\\u043e\\u0446\\u043c\\u0435\\u0442\",\"\\u0427\\u0415 \\u0422\\u0410\\u041c\"]','{\"samples_count\":24,\"source\":\"openai\",\"chat_id\":44}','2026-05-14 10:14:20','2026-05-12 16:23:12','2026-05-14 10:14:20'),
(3,1,5,'Сотрудник использует краткие и прямые формулировки, без излишней формальности. Сообщения простые и понятные, с акцентом на важную информацию.','[\"\\u041d\\u0430\\u043f\\u043e\\u043c\\u0438\\u043d\\u0430\\u0435\\u043c: \\u0432\\u044b \\u0437\\u0430\\u043f\\u0438\\u0441\\u0430\\u043d\\u044b \\u043d\\u0430 \\u043c\\u0430\\u043d\\u0438\\u043a\\u044e\\u0440 13.05 \\u0432 13:20.\",\"\\u0412\\u044b \\u0437\\u0430\\u043f\\u0438\\u0441\\u0430\\u043d\\u044b \\u043d\\u0430 \\u0441\\u0442\\u0440\\u0438\\u0436\\u043a\\u0443 14.06 \\u0432 10:00.\",\"\\u041d\\u0435 \\u0437\\u0430\\u0431\\u0443\\u0434\\u044c\\u0442\\u0435 \\u043f\\u0440\\u043e \\u0437\\u0430\\u043f\\u0438\\u0441\\u044c \\u043d\\u0430 \\u043c\\u0430\\u0441\\u0441\\u0430\\u0436 15.07.\",\"\\u0412\\u0430\\u0448 \\u0432\\u0438\\u0437\\u0438\\u0442 \\u043d\\u0430 12.08 \\u0432 15:30 \\u043f\\u043e\\u0434\\u0442\\u0432\\u0435\\u0440\\u0436\\u0434\\u0435\\u043d.\",\"\\u0417\\u0430\\u043f\\u0438\\u0441\\u044c \\u043d\\u0430 \\u043f\\u0435\\u0434\\u0438\\u043a\\u044e\\u0440 20.09 \\u0432 11:00.\",\"\\u0412\\u044b \\u0437\\u0430\\u043f\\u0438\\u0441\\u0430\\u043d\\u044b \\u043d\\u0430 \\u0443\\u043a\\u043b\\u0430\\u0434\\u043a\\u0443 25.10 \\u0432 14:00.\",\"\\u041d\\u0430\\u043f\\u043e\\u043c\\u0438\\u043d\\u0430\\u0435\\u043c \\u043e \\u0437\\u0430\\u043f\\u0438\\u0441\\u0438 \\u043d\\u0430 \\u043e\\u043a\\u0440\\u0430\\u0448\\u0438\\u0432\\u0430\\u043d\\u0438\\u0435 30.11.\",\"\\u0412\\u0430\\u0448 \\u043c\\u0430\\u043d\\u0438\\u043a\\u044e\\u0440 05.12 \\u0432 16:00.\",\"\\u0417\\u0430\\u043f\\u0438\\u0441\\u044c \\u043d\\u0430 \\u0441\\u043f\\u0430 10.01 \\u0432 12:30.\",\"\\u041d\\u0435 \\u0437\\u0430\\u0431\\u0443\\u0434\\u044c\\u0442\\u0435 \\u043f\\u0440\\u043e \\u043c\\u0430\\u043d\\u0438\\u043a\\u044e\\u0440 15.02.\",\"\\u0412\\u044b \\u0437\\u0430\\u043f\\u0438\\u0441\\u0430\\u043d\\u044b \\u043d\\u0430 \\u0441\\u0442\\u0440\\u0438\\u0436\\u043a\\u0443 20.03 \\u0432 13:00.\",\"\\u0412\\u0430\\u0448 \\u04