INSERT INTO `failed_jobs` VALUES
(47,'11cd2a4f-05ec-488b-bfb0-79227a308996','database','default','{\"uuid\":\"11cd2a4f-05ec-488b-bfb0-79227a308996\",\"displayName\":\"App\\\\Jobs\\\\ProcessWhatsappInboundJob\",\"job\":\"Illuminate\\\\Queue\\\\CallQueuedHandler@call\",\"maxTries\":5,\"maxExceptions\":null,\"failOnTimeout\":false,\"backoff\":\"5,15,30,60,120\",\"timeout\":null,\"retryUntil\":null,\"data\":{\"commandName\":\"App\\\\Jobs\\\\ProcessWhatsappInboundJob\",\"command\":\"O:34:\\\"App\\\\Jobs\\\\ProcessWhatsappInboundJob\\\":1:{s:4:\\\"data\\\";a:15:{s:7:\\\"session\\\";s:11:\\\"wa-cc542b79\\\";s:9:\\\"messageId\\\";s:70:\\\"false_120363407223719821@g.us_3AB97D6A43354AB9EA1B_188703783813343@lid\\\";s:4:\\\"from\\\";s:23:\\\"120363407223719821@g.us\\\";s:2:\\\"to\\\";s:16:\\\"77075471406@c.us\\\";s:4:\\\"body\\\";s:2543:\\\"1. Титул беті\\n\\nМұнда:\\n\\n* Аты-жөніңіз\\n* “Педагог-психолог” деген мамандығыңыз\\n* Жұмыс орны\\n* Байланыс\\n* Фото (ресми стильде)\\n\\nҚысқа әрі таза дизайн болғаны жақсы.\\n\\n⸻\\n\\n2. Өзіңіз туралы қысқаша таныстыру\\n\\n1 беттен аспасын.\\n\\nМысалы:\\n\\n* Біліміңіз\\n* Қанша жыл тәжірибе\\n* Қандай бағытта жұмыс істейсіз:\\n    * мектеп психологиясы\\n    * жасөспірімдер\\n    * ата-анамен жұмыс\\n    * коррекция\\n    * диагностика\\n    * инклюзия т.б.\\n\\nОсы жерде кәсіби мақсатыңызды да жазуға болады.\\n\\n⸻\\n\\n3. Нормативтік және кәсіби база\\n\\nМынадай құжаттарды енгізеді:\\n\\n* диплом\\n* сертификаттар\\n* біліктілік арттыру курстары\\n* категория\\n* марапаттар\\n\\nСкан\\/фото сапалы болуы маңызды.\\n\\n⸻\\n\\n4. Жұмыс тәжірибесі мен нәтижелер\\n\\nБұл — портфолионың ең маңызды бөлігі.\\n\\nМынадай бөлімдер жасаңыз:\\n\\nПсиходиагностика\\n\\n* Қандай әдістемелер қолданасыз\\n* Қандай мақсатта\\n* Қысқа нәтиже үлгілері\\n\\nТүзету-дамыту жұмысы\\n\\n* Тренингтер\\n* Жеке консультация\\n* Топтық жұмыс\\n\\nАта-анамен жұмыс\\n\\n* Жиналыс\\n* Семинар\\n* Кеңес беру\\n\\nМұғалімдермен жұмыс\\n\\n* Педкеңес\\n* Burnout профилактикасы\\n* Тимбилдинг\\n\\n⸻\\n\\n5. Авторлық материалдар\\n\\nЕгер бар болса:\\n\\n* тренинг жоспары\\n* сабақ жоспары\\n* психологиялық ойындар\\n* презентациялар\\n* буклеттер\\n\\nБұл сізді ерекше көрсетеді.\\n\\n⸻\\n\\n6. Жетістіктер мен кері байланыс\\n\\nҚосуға болады:\\n\\n* алғыс хаттар\\n* пікірлер\\n* фотоесеп\\n* іс-шарадан үзінділер\\n\\n⸻\\n\\n7. Қорытынды\\n\\nҚысқа кәсіби ұстаным:\\n\\n“Баланың психологиялық қауіпсіздігі мен тұлғалық дамуы — менің жұмысымның басты бағыты.”\\\";s:4:\\\"type\\\";s:4:\\\"chat\\\";s:9:\\\"timestamp\\\";i:1778271943;s:7:\\\"isGroup\\\";b:1;s:6:\\\"chatId\\\";s:23:\\\"120363407223719821@g.us\\\";s:8:\\\"chatName\\\";s:43:\\\"🤝ЖИ | ИИ | Ai Қазақстан🤝\\\";s:11:\\\"senderPhone\\\";N;s:15:\\\"senderAuthorJid\\\";s:19:\\\"188703783813343@lid\\\";s:10:\\\"senderName\\\";s:35:\\\"Динара Сығындықова\\\";s:11:\\\"isForwarded\\\";b:0;s:12:\\\"hasQuotedMsg\\\";b:0;}}\"}}','Illuminate\\Broadcasting\\BroadcastException: Pusher error: Payload too large.. in /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Broadcasting/Broadcasters/PusherBroadcaster.php:164\nStack trace:\n#0 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Broadcasting/BroadcastEvent.php(93): Illuminate\\Broadcasting\\Broadcasters\\PusherBroadcaster->broadcast()\n#1 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/BoundMethod.php(36): Illuminate\\Broadcasting\\BroadcastEvent->handle()\n#2 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/Util.php(43): Illuminate\\Container\\BoundMethod::Illuminate\\Container\\{closure}()\n#3 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/BoundMethod.php(95): Illuminate\\Container\\Util::unwrapIfClosure()\n#4 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/BoundMethod.php(35): Illuminate\\Container\\BoundMethod::callBoundMethod()\n#5 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/Co