(48,'71a9dd4b-fb8c-4a9c-a921-723f32cd60c6','database','default','{\"uuid\":\"71a9dd4b-fb8c-4a9c-a921-723f32cd60c6\",\"displayName\":\"App\\\\Jobs\\\\ProcessWhatsappInboundJob\",\"job\":\"Illuminate\\\\Queue\\\\CallQueuedHandler@call\",\"maxTries\":5,\"maxExceptions\":null,\"failOnTimeout\":false,\"backoff\":\"5,15,30,60,120\",\"timeout\":null,\"retryUntil\":null,\"data\":{\"commandName\":\"App\\\\Jobs\\\\ProcessWhatsappInboundJob\",\"command\":\"O:34:\\\"App\\\\Jobs\\\\ProcessWhatsappInboundJob\\\":1:{s:4:\\\"data\\\";a:15:{s:7:\\\"session\\\";s:11:\\\"wa-cc542b79\\\";s:9:\\\"messageId\\\";s:69:\\\"false_120363407223719821@g.us_3A7E8EC28AFE64459926_70592183165120@lid\\\";s:4:\\\"from\\\";s:23:\\\"120363407223719821@g.us\\\";s:2:\\\"to\\\";s:16:\\\"77075471406@c.us\\\";s:4:\\\"body\\\";s:5561:\\\"Интеллектуальное ядро: Aether Nexus\\n​Центральная нервная система комплекса. Она в реальном времени собирает данные со всех сенсоров, отсеивает легальный трафик (UTM), классифицирует угрозы, рассчитывает баллистику перехвата и управляет дронами-камикадзе.\\n​Первая линия: Рубеж раннего обнаружения (Сенсорный контур)\\n​Разворачивается непосредственно вдоль государственной границы. Ее задача — фиксация любого несанкционированного пересечения воздушного пространства задолго до подхода к критической инфраструктуре.\\n​1. Наземные мультисенсорные посты:\\n​РЛС: Маловысотные многолучевые радары (АФАР) а также частонтные сканеры, фиксирующие точные координаты (x, y, z) и скорость малых целей с минимальной эффективной площадью рассеяния.\\n​Акустические пеленгаторы: Направленные микрофоны, которые по звуковой сигнатуре определяют тип двигателя (например, ДВС «Шахеда» или электродвигатель коммерческого коптера), исключая ложные срабатывания.\\n​2. Воздушный эшелон (Выносной пост ДРЛО):\\n​Гибридные БПЛА (VTOL): Тяжелые беспилотники с ДВС+генератором, патрулирующие на высоте 3–5 км.\\n​Бортовая АФАР: Обеспечивает радиолокационное покрытие в радиусе 100–150 км, компенсируя «слепые зоны» наземных радаров из-за рельефа.\\n​Автономность: Возвращаются на базы только для дозаправки и индукционной беспроводной подзарядки электронных систем.\\n​Вторая линия: Рубеж активного перехвата (Кинетический контур)\\n​Располагается в глубине территории (5–15 км от первой линии). Ее задача — физическое уничтожение угрозы до вмешательства тяжелых комплексов ПВО.\\n​1. Автономные станции Sky Hub:\\n​Герметичные, климатически защищенные наземные боксы, находящиеся в режиме постоянного боевого дежурства.\\n​Оборудованы площадками для индукционной зарядки как перехватчиков, так и тяжелых дронов ДРЛО.\\n​2. Ударные микро-БПЛА (Перехватчики):\\n​Скоростные коптеры-камикадзе, хранящиеся внутри хабов.\\n​Оснащены стандартными высокооборотистыми винтами для максимальной скорости сближения.\\n​Двойное наведение: На маршевом участке летят \\\"вслепую\\\" по координатам от Aether Nexus (экономия энергии). На финальном этапе (последние сотни метров) включают камеру с машинным зрением, захватывают силуэт цели и самостоятельно доводят удар, становясь полностью неуязвимыми для систем РЭБ противника.\\n​Единый алгоритм работы.\\n​Обнаружение: Гибридный дрон ДРЛО или наземная РЛС фиксируют объект. Акустика подтверждает сигнатуру двигателя.\\n​Анализ: Aether Nexus не находит транспондер цели в базе и мгновенно маркирует ее как военную угрозу.\\n​Расчет: Программное ядро вычисляет вектор движения нарушителя и определяет оптимальную точку встречи.\\n​Запуск: Ближайший к расчетной точке Sky Hub открывается и выпускает микро-БПЛА.\\n​Сближение: Aether Nexus корректирует полет перехватчика по радиоканалу, выводя его в зону прямой видимости.\\n​Удар: Перехватчик включает оптику с ИИ, фиксирует нарушителя и уничтожает его кинетическим ударом.\\n​Контроль: Дрон ДРЛО фиксирует факт уничтожения с воздуха и передает отчет дежурным ПВО.\\n​Данная концепция формирует полностью закрытый и автономный щит.\\\";s:4:\\\"type\\\";s:4:\\\"chat\\\";s:9:\\\"timestamp\\\";i:1778574876;s:7:\\\"isGroup\\\";b:1;s:6:\\\"chatId\\\";s:23:\\\"120363407223719821@g.us\\\";s:8:\\\"chatName\\\";s:43:\\\"🤝ЖИ | ИИ | Ai Қазақстан🤝\\\";s:11:\\\"senderPhone\\\";N;s:15:\\\"senderAuthorJid\\\";s:18:\\\"70592183165120@lid\\\";s:10:\\\"senderName\\\";s:26:\\\"~Алия Медеуова\\\";s:11:\\\"isForwarded\\\";b:0;s:12:\\\"hasQuotedMsg\\\";b:0;}}\"}}','Illuminate\\Broadcasting\\BroadcastException: Pusher error: Payload too large.. in /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Broadcasting/Broadcasters/PusherBroadcaster.php:164\nStack trace:\n#0 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Broadcasting/BroadcastEvent.php(93): Illuminate\\Broadcasting\\Broadcasters\\PusherBroadcaster->broadcast()\n#1 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/BoundMethod.php(36): Illuminate\\Broadcasting\\BroadcastEvent->handle()\n#2 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/Util.php(43): Illuminate\\Container\\BoundMethod::Illuminate\\Container\\{closure}()\n#3 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/BoundMethod.php(95): Illuminate\\Container\\Util::unwrapIfClosure()\n#4 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/BoundMethod.php(35): Illuminate\\Container\\BoundMethod::callBoundMethod()\n#5 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Container/Container.php(696): Illuminate\\Container\\BoundMethod::call()\n#6 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Bus/Dispatcher.php(126): Illuminate\\Container\\Container->call()\n#7 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Pipeline/Pipeline.php(170): Illuminate\\Bus\\Dispatcher->Illuminate\\Bus\\{closure}()\n#8 /var/www/chatswitch.10k.kz/vendor/laravel/framework/src/Illuminate/Pipeline/Pipeline.php(127): Illuminate\\Pipeline\\Pipeline->Illuminate\\Pipeline\\{closure}()\n#9 /var/www/chatswitch.10k.kz/vendor/laravel/fram